import type {RouteObject} from 'react-router-dom';
import type {IMenuItem, Permissions} from "@lmb-it/kitsconcerto-types";

export const checkPermissions = (
    sections: IMenuItem[],
    check: ((permissions: Permissions) => boolean) | undefined,
): IMenuItem[] => {
    const routes: IMenuItem[] = [];

    sections.forEach((section) => {
        let r:IMenuItem = section;
        const permissions: Permissions = {};
        if (section.permissionsRequired) {
            permissions.permissionsRequired = section.permissionsRequired;
        }
        if (section.permissionsOptional) {
            permissions.permissionsOptional = section.permissionsOptional;
        }
        const isPermitted =(!permissions.permissionsOptional && !permissions.permissionsRequired) || !check || check(permissions);

        if (isPermitted || section.loginNotRequired) {
            r = {
                ...section
            } as IMenuItem

            if (section.links && section.links.length > 0) {
                r.links = checkPermissions(section.links, check);
            }


            routes.push(r)
        }
    });

    return routes;
};
export const mapSectionsToRoutes = (
    sections: IMenuItem[]
): RouteObject[] => {
    const id = Math.random().toString(16).slice(2);
    const routes = sections.map((section) => {
        let obj = {
            id: section.id ?? id,
            path: section.path,
            element: section.element,
        } as RouteObject;

        if (section.links && section.links.length > 0) {
            obj.children = mapSectionsToRoutes(section.links);
        }

        return obj;
    });

    return routes.filter((item) => !!item);
};

export const remapSectionsWithPathsAndPermissions = (
    sections: IMenuItem[],
    checkPermissions: ((permissions: Permissions) => boolean) | undefined,
    parentPath: string = ''
): IMenuItem[] => {
    const routes: (IMenuItem | null)[] = sections.map((section) => {
        const fullPath = `${parentPath}/${section.path}`.replace(/^\/+/, '');

        const permissions: Permissions = {};
        if (section.permissionsRequired) {
            permissions.permissionsRequired = section.permissionsRequired;
        }

        if (section.permissionsOptional) {
            permissions.permissionsOptional = section.permissionsOptional;
        }
        const isPermitted = !checkPermissions || checkPermissions(permissions);

        if ((!isPermitted && !section.loginNotRequired) || !!section.hide) {
            return null;
        }

        const obj = {
            ...section,
            path: fullPath,
        } as IMenuItem;

        if (section.links && section.links.length > 0) {
            obj.links = remapSectionsWithPathsAndPermissions(
                section.links,
                checkPermissions,
                fullPath
            );
        }

        return obj;
    });

    return routes.filter((item) => !!item) as IMenuItem[];
};
